INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('385', '105', '11663', '105', ' contactado_sin_respuesta ', ' sin_deuda ', ' mensaje_whatsapp ', ' whatsapp ', ' Cliente confirmó que el correo era para el plan de Luis Facundo Echazu (Grupo 11663 - Orden 105). Plan figura al día. Oferta de adelantar cuotas realizada; pendiente confirmación de cantidad. ', ' sin_deuda_registrada ', '{"email": "accesoriospesadosagsa@gmail.com", "tipo_plan": "adelanto", "observaciones": "Cliente informó que el email de cobranza era para este plan. Info_status indica plan UP_TO_DATE. Se ofreció gestionar cupón para adelantar cuotas.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' neutral ', '2026-06-16T19:01:45.381164+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('386', '105', '11663', '105', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Ahorrista reportó aviso por mail. Oferta de verificación del correo o gestión de cupón para adelantar cuotas. Pendiente detalle del asunto/remitente o confirmación de cantidad de cuotas. ', ' informacion_recabada ', '{"email": "accesoriospesadosagsa@gmail.com", "tipo_plan": "evaluacion", "observaciones": "Ahorrista indicó recepción de aviso por mail. Plan figura al día en info_status. Se solicitó asunto/remitente para verificar o confirmar si desea adelantar cuotas.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' neutral ', '2026-06-16T19:43:47.93477+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('387', '79', '11546', '27', ' sin_deuda ', ' sin_deuda ', ' mensaje_whatsapp ', ' whatsapp ', ' Cliente preguntó si se envió email. Historial confirma envío; verificación comercial (info_status) no devolvió datos, por eso no hay deuda registrada en el sistema. ', ' sin_deuda_registrada ', '{"email": "CALE4397@GMAIL.COM", "tipo_plan": "evaluacion", "observaciones": "Historial muestra envío de email de cobranza; info_status no devolvió datos comerciales para confirmar montos.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' colaborativo ', '2026-06-16T22:52:19.423696+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('388', '19', '11756', '168', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Se informó saldo pendiente (nextQuotaAmount) y se ofrecieron opciones de pago: pago total o pago parcial (1 cuota). ', ' informacion_recabada ', '{"email": "POBLADORESTUDIO@HOTMAIL.COM", "tipo_plan": "evaluacion", "observaciones": "Presentación inicial de situación; 49 cuotas vencidas según registro. Primera toma de contacto por chat.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' neutral ', '2026-06-22T14:04:57.11327+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('389', '19', '11756', '168', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Informada deuda y opciones de pago. Se espera confirmación del ahorrista para gestionar cupón o definir modalidad de pago. ', ' informacion_recabada ', '{"email": "POBLADORESTUDIO@HOTMAIL.COM", "tipo_plan": "evaluacion", "observaciones": "Presentación inicial de situación: 33 cuotas pagas, 49 cuotas vencidas. nextQuotaAmount $1.398.439,85. Se ofrecieron opciones de pago y propuesta de envío de cupón por mail.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' neutral ', '2026-06-22T14:05:19.250615+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('390', '32', '11817', '127', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Ahorrista escribió ''Ya realicé el pago''. Se solicitó comprobante y datos del pago para verificación (24-48 hs hábiles). ', ' informacion_recabada ', '{"email": "VALERIA23192@GMAIL.COM", "tipo_plan": "evaluacion", "observaciones": "Ahorrista informa haber realizado el pago. Se solicitó comprobante (captura o número de referencia) y detalles (fecha y medio) para verificar.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' colaborativo ', '2026-06-22T14:05:50.35789+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('391', '32', '11817', '127', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Ahorrista respondió afirmativamente a la solicitud de enviar comprobante. Pendiente recepción de fecha, medio y referencia/foto para verificación. ', ' informacion_recabada ', '{"email": "VALERIA23192@GMAIL.COM", "tipo_plan": "evaluacion", "observaciones": "Ahorrista confirmó que enviará comprobante de pago. Se solicitó fecha, medio y foto o número de referencia para verificación.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' colaborativo ', '2026-06-22T14:06:33.572504+00:00');
