INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('393', '18', '11734', '154', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Cliente indicó que necesita pagar una a la vez. Se presentó situación del plan y 3 opciones de pago; se solicitan confirmación de pago de 1 cuota y método ', ' informacion_recabada ', '{"email": "negoty19@gmail.com", "tipo_plan": "evaluacion", "observaciones": "Cliente solicita pagar una cuota a la vez; se ofrecieron opciones y se pide confirmación para tramitar cupón", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' colaborativo ', '2026-06-22T14:07:43.728028+00:00');
INSERT INTO "ovalo-cobranzas".cobranza_etapas_historial VALUES ('394', '18', '11734', '154', ' contactado_sin_respuesta ', ' conversacion_iniciada ', ' mensaje_whatsapp ', ' whatsapp ', ' Rubén solicita ponerse al día; se ofreció gestión de cupón y 3 formas de pago. Se pidió confirmación de cantidad de cuotas y medio de pago. ', ' informacion_recabada ', '{"email": "negoty19@gmail.com", "tipo_plan": "evaluacion", "observaciones": "Ahorrista manifestó intención de ponerse al día; se solicitó cantidad de cuotas a pagar y elección de medio de pago. Pendiente tramitar cupón si confirma cuotas.", "fecha_compromiso": null, "cuotas_comprometidas": 0}', ' colaborativo ', '2026-06-22T14:07:48.837973+00:00');
